def is_palindrome(title):
    title = title.lower() 
    if len(title) <= 1: 
        return True
    if title[0] != title[-1]: 
        return False
    return is_palindrome(title[1:-1]) 

def filter_palindromes(titles):
    if not titles: 
        return []
    first = titles[0] 
    rest = titles[1:] 
    if is_palindrome(first): 
        return [first] + filter_palindromes(rest)
    else:
        return filter_palindromes(rest)
